sys_ui_action.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
var gr = new GlideAggregate('x_153465_discovert_discover_routing_template');

// STRY0072078 - change the name of the button for create template
//"New" Template Form --- Actual: "Create Process Template", Expected: "Create Template" - UI Action Name udpate

		gr.addQuery('template_name', current.template_name);
		gr.addQuery('process_level', current.process_level);

		if(current.process_level == 'ou_process')
		gr.addQuery('process_ou', current.process_ou);

		gr.query();

		if(gr.next()){
			gs.addErrorMessage("The name '" + current.template_name + "' is already being used.  Please change the Template Name to a unique name");
		}else{
			current.insert();
			gs.addInfoMessage("Template <b>" + current.template_name  + '</b> has been created. <a href="../discovertaskerportal?id=discovertasker_processtemplatedetails&table=x_153465_discovert_route_tasks&sys_id='+current.parent_task_def+'">Click here to build it</a>');

		}

